var COURSE_PL_EL = [{day: 1, title: `Pierwsze powitania w Atenach`, title_native: `Πρώτοι χαιρετισμοί`, focus: `Zaczynasz podróż po Grecji od Aten i uczysz się najprostszych zwrotów do przywitania, pożegnania i uprzejmego rozpoczęcia rozmowy. Te słowa przydadzą się w hotelu, kawiarni, sklepie i na ulicy.`, vocab: [{el: `γεια`, pl: `cześć`, ipa: `ja`},{el: `καλημέρα`, pl: `dzień dobry`, ipa: `kalimera`},{el: `καλησπέρα`, pl: `dobry wieczór`, ipa: `kalispera`},{el: `καληνύχτα`, pl: `dobranoc`, ipa: `kalinichta`},{el: `αντίο`, pl: `do widzenia`, ipa: `adio`},{el: `παρακαλώ`, pl: `proszę`, ipa: `parakalo`},{el: `ευχαριστώ`, pl: `dziękuję`, ipa: `efcharisto`},{el: `ναι`, pl: `tak`, ipa: `ne`},{el: `όχι`, pl: `nie`, ipa: `ochi`},{el: `συγγνώμη`, pl: `przepraszam`, ipa: `signomi`}], phrases: [{el: `Γεια σας.`, pl: `Dzień dobry / Witam.`, ipa: `ja sas`},{el: `Καλημέρα σας.`, pl: `Dzień dobry państwu.`, ipa: `kalimera sas`},{el: `Ευχαριστώ πολύ.`, pl: `Bardzo dziękuję.`, ipa: `efcharisto poli`},{el: `Παρακαλώ.`, pl: `Proszę / Nie ma za co.`, ipa: `parakalo`},{el: `Συγγνώμη.`, pl: `Przepraszam.`, ipa: `signomi`},{el: `Αντίο, τα λέμε.`, pl: `Do widzenia, do zobaczenia.`, ipa: `adio, ta leme`}], grammar: `W greckim często rozróżnia się formę nieformalną i uprzejmą. Γεια σου mówisz do jednej osoby na luzie, a Γεια σας do obcych, starszych osób lub grupy. W podróży bezpieczniej zaczynać od formy z σας, bo brzmi uprzejmie i naturalnie.`, practice: [`Przywitaj recepcjonistę w hotelu po grecku.`,`Powiedz „bardzo dziękuję” w greckiej kawiarni.`,`Wybierz, czy do kelnera lepiej powiedzieć Γεια σου czy Γεια σας.`,`Przećwicz pożegnanie z osobą, którą dopiero poznałeś.`,`Powiedz po grecku: „Przepraszam, proszę”.`]},{day: 2, title: `Przedstawianie się`, title_native: `Συστάσεις`, focus: `W Salonikach poznajesz innych podróżnych i uczysz się mówić, jak masz na imię oraz skąd jesteś. To dobry moment na pierwsze krótkie rozmowy.`, vocab: [{el: `όνομα`, pl: `imię`, ipa: `onoma`},{el: `με λένε`, pl: `mam na imię`, ipa: `me lene`},{el: `είμαι`, pl: `jestem`, ipa: `ime`},{el: `από`, pl: `z, od`, ipa: `apo`},{el: `Πολωνία`, pl: `Polska`, ipa: `polonia`},{el: `Πολωνός`, pl: `Polak`, ipa: `polonos`},{el: `Πολωνή`, pl: `Polka`, ipa: `poloni`},{el: `τουρίστας`, pl: `turysta`, ipa: `turistas`},{el: `φίλος`, pl: `przyjaciel`, ipa: `filos`},{el: `φίλη`, pl: `przyjaciółka`, ipa: `fili`}], phrases: [{el: `Με λένε Άννα.`, pl: `Mam na imię Anna.`, ipa: `me lene anna`},{el: `Είμαι από την Πολωνία.`, pl: `Jestem z Polski.`, ipa: `ime apo tin polonia`},{el: `Είμαι τουρίστας.`, pl: `Jestem turystą.`, ipa: `ime turistas`},{el: `Χάρηκα.`, pl: `Miło mi.`, ipa: `charika`},{el: `Πώς σε λένε;`, pl: `Jak masz na imię?`, ipa: `pos se lene`},{el: `Από πού είσαι;`, pl: `Skąd jesteś?`, ipa: `apo pu ise`}], grammar: `Greckie είμαι oznacza „jestem” i jest bardzo przydatne już od pierwszych dni. W zdaniu „Jestem z Polski” pojawia się από, czyli „z”. Przy krajach często używa się rodzajnika, dlatego usłyszysz την Πολωνία, czyli dosłownie „tę Polskę”.`, practice: [`Powiedz po grecku swoje imię.`,`Powiedz, że jesteś z Polski.`,`Zapytaj kogoś, jak ma na imię.`,`Odpowiedz na pytanie Από πού είσαι;`,`Ułóż krótką rozmowę: powitanie, imię, kraj, „miło mi”.`]},{day: 3, title: `Podstawowe pytania i odpowiedzi`, title_native: `Βασικές ερωτήσεις`, focus: `W centrum Heraklionu chcesz zadawać proste pytania bez stresu. Nauczysz się słów pytających i krótkich odpowiedzi przydatnych podczas zwiedzania.`, vocab: [{el: `ποιος`, pl: `kto`, ipa: `pjos`},{el: `πού`, pl: `gdzie`, ipa: `pu`},{el: `πότε`, pl: `kiedy`, ipa: `pote`},{el: `τι`, pl: `co`, ipa: `ti`},{el: `πώς`, pl: `jak`, ipa: `pos`},{el: `γιατί`, pl: `dlaczego`, ipa: `jati`},{el: `εδώ`, pl: `tutaj`, ipa: `edho`},{el: `εκεί`, pl: `tam`, ipa: `eki`},{el: `τώρα`, pl: `teraz`, ipa: `tora`},{el: `μετά`, pl: `potem`, ipa: `meta`}], phrases: [{el: `Πού είναι;`, pl: `Gdzie to jest?`, ipa: `pu ine`},{el: `Τι είναι αυτό;`, pl: `Co to jest?`, ipa: `ti ine afto`},{el: `Πώς πάω εκεί;`, pl: `Jak tam dojść?`, ipa: `pos pao eki`},{el: `Πότε ανοίγει;`, pl: `Kiedy otwiera?`, ipa: `pote aniji`},{el: `Είναι εδώ;`, pl: `Czy to jest tutaj?`, ipa: `ine edho`},{el: `Δεν ξέρω.`, pl: `Nie wiem.`, ipa: `dhen ksero`}], grammar: `W greckim pytanie często tworzy się samą intonacją, bez zmiany szyku zdania. Είναι εδώ może znaczyć „To jest tutaj” albo „Czy to jest tutaj?” zależnie od tonu głosu. W piśmie pytajnik grecki wygląda jak średnik: ;`, practice: [`Zapytaj po grecku: „Gdzie to jest?”`,`Zapytaj, co to jest, wskazując na danie w menu.`,`Odpowiedz po grecku: „Nie wiem.”`,`Powiedz „teraz” i „potem” w dwóch krótkich zdaniach.`,`Przećwicz pytanie o godzinę otwarcia muzeum.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `Αριθμοί από το μηδέν ως το είκοσι`, focus: `Na targu w Atenach i przy kupowaniu biletów musisz rozumieć ceny, numery i ilości. Dziś poznasz najważniejsze liczby na start.`, vocab: [{el: `μηδέν`, pl: `zero`, ipa: `midhen`},{el: `ένα`, pl: `jeden`, ipa: `ena`},{el: `δύο`, pl: `dwa`, ipa: `dhio`},{el: `τρία`, pl: `trzy`, ipa: `tria`},{el: `τέσσερα`, pl: `cztery`, ipa: `tesera`},{el: `πέντε`, pl: `pięć`, ipa: `pende`},{el: `έξι`, pl: `sześć`, ipa: `eksi`},{el: `επτά`, pl: `siedem`, ipa: `epta`},{el: `οκτώ`, pl: `osiem`, ipa: `okto`},{el: `δέκα`, pl: `dziesięć`, ipa: `dheka`}], phrases: [{el: `Ένα εισιτήριο, παρακαλώ.`, pl: `Jeden bilet, proszę.`, ipa: `ena isitirio, parakalo`},{el: `Δύο καφέδες, παρακαλώ.`, pl: `Dwie kawy, proszę.`, ipa: `dhio kafedhes, parakalo`},{el: `Πόσο κάνει;`, pl: `Ile kosztuje?`, ipa: `poso kani`},{el: `Κάνει πέντε ευρώ.`, pl: `Kosztuje pięć euro.`, ipa: `kani pende evro`},{el: `Θέλω τρία.`, pl: `Chcę trzy.`, ipa: `thelo tria`},{el: `Έχω δέκα ευρώ.`, pl: `Mam dziesięć euro.`, ipa: `echo dheka evro`}], grammar: `Liczby w greckim często stoją przed rzeczownikiem, podobnie jak po polsku. Ένα εισιτήριο to „jeden bilet”, a δύο καφέδες to „dwie kawy”. W praktyce turystycznej najważniejsze jest szybkie rozpoznawanie liczb w cenach i przy zamówieniach.`, practice: [`Policz po grecku od 0 do 10.`,`Zamów jeden bilet.`,`Zamów dwie kawy.`,`Zapytaj, ile coś kosztuje.`,`Odpowiedz, że kosztuje pięć euro.`]},{day: 5, title: `Więcej liczb, ceny i euro`, title_native: `Περισσότεροι αριθμοί και τιμές`, focus: `W sklepie z pamiątkami na Rodos chcesz zapytać o ceny i zrozumieć odpowiedź. Rozszerzysz liczby do 100 i połączysz je z pieniędzmi.`, vocab: [{el: `έντεκα`, pl: `jedenaście`, ipa: `endeka`},{el: `δώδεκα`, pl: `dwanaście`, ipa: `dhodheka`},{el: `δεκατρία`, pl: `trzynaście`, ipa: `dhekatria`},{el: `δεκαπέντε`, pl: `piętnaście`, ipa: `dhekapende`},{el: `είκοσι`, pl: `dwadzieścia`, ipa: `ikosi`},{el: `τριάντα`, pl: `trzydzieści`, ipa: `trianda`},{el: `σαράντα`, pl: `czterdzieści`, ipa: `saranda`},{el: `πενήντα`, pl: `pięćdziesiąt`, ipa: `peninda`},{el: `εκατό`, pl: `sto`, ipa: `ekato`},{el: `ευρώ`, pl: `euro`, ipa: `evro`}], phrases: [{el: `Πόσο κοστίζει αυτό;`, pl: `Ile to kosztuje?`, ipa: `poso kostizi afto`},{el: `Κοστίζει είκοσι ευρώ.`, pl: `To kosztuje dwadzieścia euro.`, ipa: `kostizi ikosi evro`},{el: `Είναι ακριβό.`, pl: `To jest drogie.`, ipa: `ine akrivo`},{el: `Είναι φτηνό.`, pl: `To jest tanie.`, ipa: `ine ftino`},{el: `Έχετε κάτι πιο φτηνό;`, pl: `Czy macie coś tańszego?`, ipa: `echete kati pio ftino`},{el: `Μπορώ να πληρώσω με κάρτα;`, pl: `Czy mogę zapłacić kartą?`, ipa: `boro na pliroso me karta`}], grammar: `Greckie πιο tworzy stopień wyższy przymiotnika, podobnie jak „bardziej” lub „-szy” po polsku. Πιο φτηνό znaczy „tańsze”, a πιο μεγάλο znaczy „większe”. To bardzo praktyczna konstrukcja w sklepach i restauracjach.`, practice: [`Zapytaj o cenę pamiątki.`,`Powiedz, że coś jest drogie.`,`Poproś o coś tańszego.`,`Zapytaj, czy możesz zapłacić kartą.`,`Powiedz po grecku: „To kosztuje trzydzieści euro.”`]},{day: 6, title: `Dni tygodnia i czas`, title_native: `Ημέρες και ώρα`, focus: `Planujesz zwiedzanie Santorini i musisz rozumieć dni, godziny oraz proste informacje o czasie. Dziś nauczysz się umawiać plany.`, vocab: [{el: `Δευτέρα`, pl: `poniedziałek`, ipa: `dheftera`},{el: `Τρίτη`, pl: `wtorek`, ipa: `triti`},{el: `Τετάρτη`, pl: `środa`, ipa: `tetarti`},{el: `Πέμπτη`, pl: `czwartek`, ipa: `pempti`},{el: `Παρασκευή`, pl: `piątek`, ipa: `paraskevi`},{el: `Σάββατο`, pl: `sobota`, ipa: `savato`},{el: `Κυριακή`, pl: `niedziela`, ipa: `kiriaki`},{el: `σήμερα`, pl: `dzisiaj`, ipa: `simera`},{el: `αύριο`, pl: `jutro`, ipa: `avrio`},{el: `ώρα`, pl: `godzina`, ipa: `ora`}], phrases: [{el: `Τι ώρα είναι;`, pl: `Która jest godzina?`, ipa: `ti ora ine`},{el: `Είναι μία.`, pl: `Jest pierwsza.`, ipa: `ine mia`},{el: `Σήμερα είναι Δευτέρα.`, pl: `Dzisiaj jest poniedziałek.`, ipa: `simera ine dheftera`},{el: `Αύριο πάμε στην παραλία.`, pl: `Jutro idziemy na plażę.`, ipa: `avrio pame stin paralia`},{el: `Τι ώρα ανοίγει;`, pl: `O której otwiera?`, ipa: `ti ora aniji`},{el: `Τι ώρα κλείνει;`, pl: `O której zamyka?`, ipa: `ti ora klini`}], grammar: `Greckie σήμερα i αύριο są bardzo częste w rozmowach o planach. Czasownik πάμε oznacza „idziemy” albo „jedziemy”, zależnie od kontekstu. W podróży możesz używać go swobodnie, gdy mówisz o ruszaniu gdzieś razem.`, practice: [`Wymień po grecku trzy dni tygodnia.`,`Zapytaj o godzinę.`,`Powiedz, że jutro idziesz na plażę.`,`Zapytaj, o której otwiera muzeum.`,`Zapytaj, o której zamyka sklep.`]},{day: 7, title: `Kierunki i miejsca w mieście`, title_native: `Κατευθύνσεις και μέρη στην πόλη`, focus: `Spacerujesz po Starym Mieście w Chanii i chcesz znaleźć port, aptekę oraz przystanek. Nauczysz się pytać o drogę i rozumieć podstawowe kierunki.`, vocab: [{el: `δεξιά`, pl: `prawo`, ipa: `dheksia`},{el: `αριστερά`, pl: `lewo`, ipa: `aristera`},{el: `ευθεία`, pl: `prosto`, ipa: `efthia`},{el: `κοντά`, pl: `blisko`, ipa: `konda`},{el: `μακριά`, pl: `daleko`, ipa: `makria`},{el: `δρόμος`, pl: `droga, ulica`, ipa: `dhromos`},{el: `πλατεία`, pl: `plac`, ipa: `platia`},{el: `λιμάνι`, pl: `port`, ipa: `limani`},{el: `στάση`, pl: `przystanek`, ipa: `stasi`},{el: `φαρμακείο`, pl: `apteka`, ipa: `farmakio`}], phrases: [{el: `Πού είναι το λιμάνι;`, pl: `Gdzie jest port?`, ipa: `pu ine to limani`},{el: `Πηγαίνετε ευθεία.`, pl: `Proszę iść prosto.`, ipa: `pijienete efthia`},{el: `Στρίψτε δεξιά.`, pl: `Proszę skręcić w prawo.`, ipa: `strips-te dheksia`},{el: `Στρίψτε αριστερά.`, pl: `Proszę skręcić w lewo.`, ipa: `strips-te aristera`},{el: `Είναι κοντά;`, pl: `Czy to jest blisko?`, ipa: `ine konda`},{el: `Είναι μακριά;`, pl: `Czy to jest daleko?`, ipa: `ine makria`}], grammar: `Tryb rozkazujący w uprzejmej formie często kończy się na -τε, jak Πηγαίνετε albo Στρίψτε. Nie musisz znać całej odmiany, aby używać tych form w mieście. Wystarczy rozpoznawać je jako wskazówki: „idźcie/proszę iść” i „skręćcie/proszę skręcić”.`, practice: [`Zapytaj, gdzie jest port.`,`Poproś kogoś, aby powiedział, czy to daleko.`,`Powiedz: „Prosto i w prawo.”`,`Rozpoznaj różnicę między δεξιά i αριστερά.`,`Zapytaj o aptekę w centrum miasta.`]},{day: 8, title: `W hotelu i przy meldunku`, title_native: `Στο ξενοδοχείο`, focus: `Przyjeżdżasz do hotelu w Nafplio i musisz się zameldować. Poznasz słowa potrzebne przy recepcji, rezerwacji i pokoju.`, vocab: [{el: `ξενοδοχείο`, pl: `hotel`, ipa: `ksenodhochío`},{el: `ρεσεψιόν`, pl: `recepcja`, ipa: `resepsjon`},{el: `κράτηση`, pl: `rezerwacja`, ipa: `kratisi`},{el: `δωμάτιο`, pl: `pokój`, ipa: `dhomatio`},{el: `κλειδί`, pl: `klucz`, ipa: `klidhi`},{el: `διαβατήριο`, pl: `paszport`, ipa: `dhiavatirio`},{el: `νύχτα`, pl: `noc`, ipa: `nichta`},{el: `πρωινό`, pl: `śniadanie`, ipa: `proino`},{el: `όροφος`, pl: `piętro`, ipa: `orofos`},{el: `ασανσέρ`, pl: `winda`, ipa: `asanser`}], phrases: [{el: `Έχω κράτηση.`, pl: `Mam rezerwację.`, ipa: `echo kratisi`},{el: `Το όνομά μου είναι Κάνον.`, pl: `Moje nazwisko to Cannon.`, ipa: `to onoma mu ine kanon`},{el: `Μπορώ να κάνω check-in;`, pl: `Czy mogę się zameldować?`, ipa: `boro na kano czek-in`},{el: `Πού είναι το δωμάτιο;`, pl: `Gdzie jest pokój?`, ipa: `pu ine to dhomatio`},{el: `Το πρωινό συμπεριλαμβάνεται;`, pl: `Czy śniadanie jest wliczone?`, ipa: `to proino simperilamvanete`},{el: `Χρειάζεστε το διαβατήριό μου;`, pl: `Czy potrzebują państwo mojego paszportu?`, ipa: `chriazeste to dhiavatirio mu`}], grammar: `Μου oznacza „mój/moja/moje” po rzeczowniku, np. το διαβατήριό μου, czyli „mój paszport”. W greckim zaimek dzierżawczy często stoi po rzeczowniku, nie przed nim. To odwrotnie niż w polskim, ale bardzo regularne.`, practice: [`Powiedz recepcjoniście, że masz rezerwację.`,`Zapytaj, gdzie jest twój pokój.`,`Zapytaj, czy śniadanie jest wliczone.`,`Powiedz „mój paszport” po grecku.`,`Odegraj krótką scenkę przy recepcji.`]},{day: 9, title: `Kawiarnia i proste zamówienia`, title_native: `Στο καφέ`, focus: `Siadasz w kawiarni w Atenach i zamawiasz kawę po grecku. Nauczysz się mówić, czego chcesz, i prosić o rachunek.`, vocab: [{el: `καφές`, pl: `kawa`, ipa: `kafes`},{el: `νερό`, pl: `woda`, ipa: `nero`},{el: `τσάι`, pl: `herbata`, ipa: `czai`},{el: `γάλα`, pl: `mleko`, ipa: `ghala`},{el: `ζάχαρη`, pl: `cukier`, ipa: `zachari`},{el: `ποτήρι`, pl: `szklanka`, ipa: `potiri`},{el: `φλιτζάνι`, pl: `filiżanka`, ipa: `flidzani`},{el: `τραπέζι`, pl: `stolik`, ipa: `trapezi`},{el: `λογαριασμός`, pl: `rachunek`, ipa: `logariasmos`},{el: `σερβιτόρος`, pl: `kelner`, ipa: `servitoros`}], phrases: [{el: `Θέλω έναν καφέ.`, pl: `Chcę kawę.`, ipa: `thelo enan kafe`},{el: `Έναν καφέ, παρακαλώ.`, pl: `Kawę, proszę.`, ipa: `enan kafe, parakalo`},{el: `Με γάλα;`, pl: `Z mlekiem?`, ipa: `me ghala`},{el: `Χωρίς ζάχαρη.`, pl: `Bez cukru.`, ipa: `choris zachari`},{el: `Ένα νερό, παρακαλώ.`, pl: `Wodę, proszę.`, ipa: `ena nero, parakalo`},{el: `Τον λογαριασμό, παρακαλώ.`, pl: `Rachunek, proszę.`, ipa: `ton logariasmo, parakalo`}], grammar: `Θέλω znaczy „chcę” i jest jednym z najważniejszych czasowników dla podróżnika. Po nim możesz dodać rzeczownik: Θέλω καφέ, Θέλω νερό. W bardziej naturalnym zamówieniu często używa się też samego rzeczownika z παρακαλώ.`, practice: [`Zamów kawę po grecku.`,`Poproś o wodę.`,`Powiedz, że chcesz kawę bez cukru.`,`Poproś o rachunek.`,`Zapytaj kolegę, czy chce herbatę.`]},{day: 10, title: `Śniadanie i jedzenie na szybko`, title_native: `Πρωινό και γρήγορο φαγητό`, focus: `Kupujesz śniadanie w piekarni w Salonikach. Poznasz słowa związane z pieczywem, przekąskami i prostym jedzeniem.`, vocab: [{el: `ψωμί`, pl: `chleb`, ipa: `psomi`},{el: `τυρόπιτα`, pl: `placek z serem`, ipa: `tiropita`},{el: `σπανακόπιτα`, pl: `placek ze szpinakiem`, ipa: `spanakopita`},{el: `κουλούρι`, pl: `obwarzanek sezamowy`, ipa: `kuluri`},{el: `μέλι`, pl: `miód`, ipa: `meli`},{el: `γιαούρτι`, pl: `jogurt`, ipa: `jaurti`},{el: `αυγό`, pl: `jajko`, ipa: `avgo`},{el: `χυμός`, pl: `sok`, ipa: `chimos`},{el: `πορτοκάλι`, pl: `pomarańcza`, ipa: `portokali`},{el: `πιάτο`, pl: `talerz`, ipa: `piato`}], phrases: [{el: `Έχετε τυρόπιτα;`, pl: `Czy macie placek z serem?`, ipa: `echete tiropita`},{el: `Θα ήθελα ένα κουλούρι.`, pl: `Chciałbym jeden obwarzanek.`, ipa: `tha ithela ena kuluri`},{el: `Έναν χυμό πορτοκάλι, παρακαλώ.`, pl: `Sok pomarańczowy, proszę.`, ipa: `enan chimo portokali, parakalo`},{el: `Είναι φρέσκο;`, pl: `Czy to jest świeże?`, ipa: `ine fresko`},{el: `Για εδώ ή πακέτο;`, pl: `Na miejscu czy na wynos?`, ipa: `ja edho i paketo`},{el: `Πακέτο, παρακαλώ.`, pl: `Na wynos, proszę.`, ipa: `paketo, parakalo`}], grammar: `Θα ήθελα znaczy „chciałbym/chciałabym” i brzmi uprzejmiej niż Θέλω. W piekarni, kawiarni i restauracji to bardzo bezpieczna forma. Możesz jej używać prawie zawsze przy zamawianiu.`, practice: [`Zamów obwarzanek sezamowy na wynos.`,`Zapytaj, czy mają placek ze szpinakiem.`,`Poproś o sok pomarańczowy.`,`Powiedz, że chcesz jeść na miejscu.`,`Porównaj Θέλω i Θα ήθελα w dwóch zdaniach.`]},{day: 11, title: `W restauracji`, title_native: `Στο εστιατόριο`, focus: `Jesz kolację w tawernie na Krecie i chcesz zamówić dania bez pomyłek. Nauczysz się pytać o menu, składniki i rekomendacje.`, vocab: [{el: `εστιατόριο`, pl: `restauracja`, ipa: `estjatorio`},{el: `ταβέρνα`, pl: `tawerna`, ipa: `taverna`},{el: `μενού`, pl: `menu`, ipa: `menu`},{el: `φαγητό`, pl: `jedzenie`, ipa: `fajito`},{el: `κρέας`, pl: `mięso`, ipa: `kreas`},{el: `ψάρι`, pl: `ryba`, ipa: `psari`},{el: `σαλάτα`, pl: `sałatka`, ipa: `salata`},{el: `τυρί`, pl: `ser`, ipa: `tiri`},{el: `κρασί`, pl: `wino`, ipa: `krasi`},{el: `επιδόρπιο`, pl: `deser`, ipa: `epidhorpio`}], phrases: [{el: `Μπορώ να δω το μενού;`, pl: `Czy mogę zobaczyć menu?`, ipa: `boro na dho to menu`},{el: `Τι προτείνετε;`, pl: `Co pan/pani poleca?`, ipa: `ti protinete`},{el: `Θα ήθελα ψάρι.`, pl: `Chciałbym rybę.`, ipa: `tha ithela psari`},{el: `Έχετε κάτι χωρίς κρέας;`, pl: `Czy macie coś bez mięsa?`, ipa: `echete kati choris kreas`},{el: `Ήταν πολύ νόστιμο.`, pl: `Było bardzo smaczne.`, ipa: `itan poli nostimo`},{el: `Μπορούμε να πληρώσουμε;`, pl: `Czy możemy zapłacić?`, ipa: `borume na plirosume`}], grammar: `Χωρίς oznacza „bez” i jest kluczowe przy ograniczeniach dietetycznych. Χωρίς κρέας to „bez mięsa”, χωρίς ζάχαρη to „bez cukru”, χωρίς γάλα to „bez mleka”. To szybki sposób na wyjaśnienie preferencji bez skomplikowanej gramatyki.`, practice: [`Poproś o menu.`,`Zapytaj kelnera, co poleca.`,`Powiedz, że chcesz coś bez mięsa.`,`Powiedz, że jedzenie było bardzo smaczne.`,`Poproś o możliwość zapłaty.`]},{day: 12, title: `Alergie i preferencje jedzeniowe`, title_native: `Αλλεργίες και προτιμήσεις`, focus: `W podróży po Grecji musisz jasno mówić o alergiach i tym, czego nie jesz. Dziś nauczysz się bezpiecznych zwrotów do restauracji.`, vocab: [{el: `αλλεργία`, pl: `alergia`, ipa: `alergia`},{el: `ξηροί καρποί`, pl: `orzechy`, ipa: `ksiri karpi`},{el: `γάλα`, pl: `mleko`, ipa: `ghala`},{el: `γλουτένη`, pl: `gluten`, ipa: `gluteni`},{el: `θαλασσινά`, pl: `owoce morza`, ipa: `thalasina`},{el: `χοιρινό`, pl: `wieprzowina`, ipa: `chirino`},{el: `κοτόπουλο`, pl: `kurczak`, ipa: `kotopulo`},{el: `λαχανικά`, pl: `warzywa`, ipa: `lachanika`},{el: `νηστίσιμο`, pl: `postne, bez produktów zwierzęcych`, ipa: `nistissimo`},{el: `χορτοφάγος`, pl: `wegetarianin`, ipa: `chortofagos`}], phrases: [{el: `Έχω αλλεργία στους ξηρούς καρπούς.`, pl: `Mam alergię na orzechy.`, ipa: `echo alergia stus ksirus karpus`},{el: `Δεν τρώω χοιρινό.`, pl: `Nie jem wieprzowiny.`, ipa: `dhen troo chirino`},{el: `Είμαι χορτοφάγος.`, pl: `Jestem wegetarianinem.`, ipa: `ime chortofagos`},{el: `Έχει γλουτένη;`, pl: `Czy to ma gluten?`, ipa: `echi gluteni`},{el: `Είναι ασφαλές για μένα;`, pl: `Czy to jest dla mnie bezpieczne?`, ipa: `ine asfales ja mena`},{el: `Μπορείτε να βοηθήσετε;`, pl: `Czy może pan/pani pomóc?`, ipa: `borite na voithisete`}], grammar: `Δεν przed czasownikiem tworzy przeczenie. Δεν τρώω znaczy „nie jem”, δεν ξέρω „nie wiem”, δεν θέλω „nie chcę”. W sytuacjach zdrowotnych mów prosto i bez skracania informacji.`, practice: [`Powiedz, że masz alergię na orzechy.`,`Zapytaj, czy danie zawiera gluten.`,`Powiedz, że nie jesz wieprzowiny.`,`Zapytaj, czy jedzenie jest dla ciebie bezpieczne.`,`Poproś obsługę o pomoc w restauracji.`]},{day: 13, title: `Transport publiczny`, title_native: `Δημόσια συγκοινωνία`, focus: `Poruszasz się metrem i autobusem po Atenach. Nauczysz się kupować bilety, pytać o przystanki i mówić, dokąd jedziesz.`, vocab: [{el: `μετρό`, pl: `metro`, ipa: `metro`},{el: `λεωφορείο`, pl: `autobus`, ipa: `leoforio`},{el: `τραμ`, pl: `tramwaj`, ipa: `tram`},{el: `τρένο`, pl: `pociąg`, ipa: `treno`},{el: `εισιτήριο`, pl: `bilet`, ipa: `isitirio`},{el: `σταθμός`, pl: `stacja`, ipa: `stathmos`},{el: `γραμμή`, pl: `linia`, ipa: `grammi`},{el: `στάση`, pl: `przystanek`, ipa: `stasi`},{el: `κέντρο`, pl: `centrum`, ipa: `kendro`},{el: `αεροδρόμιο`, pl: `lotnisko`, ipa: `aerodhromio`}], phrases: [{el: `Ένα εισιτήριο για το μετρό.`, pl: `Jeden bilet na metro.`, ipa: `ena isitirio ja to metro`},{el: `Πάει στο κέντρο;`, pl: `Czy to jedzie do centrum?`, ipa: `pai sto kendro`},{el: `Ποια γραμμή είναι;`, pl: `Która to linia?`, ipa: `pia grammi ine`},{el: `Πού είναι ο σταθμός;`, pl: `Gdzie jest stacja?`, ipa: `pu ine o stathmos`},{el: `Κατεβαίνω εδώ.`, pl: `Wysiadam tutaj.`, ipa: `kateveno edho`},{el: `Πάω στο αεροδρόμιο.`, pl: `Jadę na lotnisko.`, ipa: `pao sto aerodhromio`}], grammar: `Greckie πάω może oznaczać „idę” lub „jadę”. Kontekst pokazuje, czy chodzi o spacer, metro czy autobus. To upraszcza mówienie: Πάω στο κέντρο może znaczyć „Idę/jadę do centrum”.`, practice: [`Kup bilet na metro.`,`Zapytaj, czy autobus jedzie do centrum.`,`Powiedz, że jedziesz na lotnisko.`,`Zapytaj, gdzie jest stacja.`,`Powiedz, że wysiadasz tutaj.`]},{day: 14, title: `Taksówka i aplikacje przejazdowe`, title_native: `Ταξί και διαδρομές`, focus: `Bierzesz taksówkę z portu w Pireusie do hotelu. Nauczysz się podawać adres, pytać o cenę i rozmawiać z kierowcą.`, vocab: [{el: `ταξί`, pl: `taksówka`, ipa: `taksi`},{el: `οδηγός`, pl: `kierowca`, ipa: `odhigos`},{el: `διεύθυνση`, pl: `adres`, ipa: `dhiefthinsi`},{el: `ξενοδοχείο`, pl: `hotel`, ipa: `ksenodhochío`},{el: `λιμάνι`, pl: `port`, ipa: `limani`},{el: `αεροδρόμιο`, pl: `lotnisko`, ipa: `aerodhromio`},{el: `διαδρομή`, pl: `trasa`, ipa: `dhiadhromi`},{el: `κίνηση`, pl: `ruch uliczny`, ipa: `kinisi`},{el: `γρήγορα`, pl: `szybko`, ipa: `grigora`},{el: `αργά`, pl: `wolno`, ipa: `arga`}], phrases: [{el: `Στο ξενοδοχείο, παρακαλώ.`, pl: `Do hotelu, proszę.`, ipa: `sto ksenodhochío, parakalo`},{el: `Αυτή είναι η διεύθυνση.`, pl: `To jest adres.`, ipa: `afti ine i dhiefthinsi`},{el: `Πόσο περίπου κοστίζει;`, pl: `Ile mniej więcej kosztuje?`, ipa: `poso peripu kostizi`},{el: `Έχει πολλή κίνηση;`, pl: `Czy jest duży ruch?`, ipa: `echi poli kinisi`},{el: `Μπορείτε να πάτε πιο γρήγορα;`, pl: `Czy może pan jechać szybciej?`, ipa: `borite na pate pio grigora`},{el: `Εδώ είναι καλά.`, pl: `Tutaj jest dobrze.`, ipa: `edho ine kala`}], grammar: `Πιο oznacza „bardziej” i pomaga porównywać: πιο γρήγορα to „szybciej”, πιο αργά to „wolniej”. W taksówce najlepiej mówić krótko i grzecznie, używając Μπορείτε, czyli „czy może pan/pani”.`, practice: [`Powiedz taksówkarzowi, że jedziesz do hotelu.`,`Pokaż adres i powiedz po grecku, że to jest adres.`,`Zapytaj o przybliżoną cenę.`,`Zapytaj, czy jest duży ruch.`,`Powiedz kierowcy, że tutaj jest dobrze.`]},{day: 15, title: `Lotnisko i bagaż`, title_native: `Αεροδρόμιο και αποσκευές`, focus: `Jesteś na lotnisku w Atenach i musisz znaleźć bramkę, bagaż oraz odprawę. Dziś poznasz słowa, które zmniejszają stres podczas lotu.`, vocab: [{el: `πτήση`, pl: `lot`, ipa: `ptisi`},{el: `αναχώρηση`, pl: `odlot`, ipa: `anachorisi`},{el: `άφιξη`, pl: `przylot`, ipa: `afiksi`},{el: `πύλη`, pl: `bramka`, ipa: `pili`},{el: `αποσκευές`, pl: `bagaże`, ipa: `aposkeves`},{el: `βαλίτσα`, pl: `walizka`, ipa: `valitsa`},{el: `χειραποσκευή`, pl: `bagaż podręczny`, ipa: `chiraposkevi`},{el: `έλεγχος`, pl: `kontrola`, ipa: `elenchos`},{el: `διαβατήριο`, pl: `paszport`, ipa: `dhiavatirio`},{el: `κάρτα επιβίβασης`, pl: `karta pokładowa`, ipa: `karta epivivasis`}], phrases: [{el: `Πού είναι η πύλη;`, pl: `Gdzie jest bramka?`, ipa: `pu ine i pili`},{el: `Έχασα τη βαλίτσα μου.`, pl: `Zgubiłem swoją walizkę.`, ipa: `echasa ti valitsa mu`},{el: `Αυτή είναι η πτήση μου.`, pl: `To jest mój lot.`, ipa: `afti ine i ptisi mu`},{el: `Χρειάζομαι βοήθεια.`, pl: `Potrzebuję pomocy.`, ipa: `chriazome voithia`},{el: `Πού είναι ο έλεγχος διαβατηρίων;`, pl: `Gdzie jest kontrola paszportowa?`, ipa: `pu ine o elenchos dhiavatirion`},{el: `Η πτήση έχει καθυστέρηση;`, pl: `Czy lot jest opóźniony?`, ipa: `i ptisi echi kathisterisi`}], grammar: `Μου po rzeczowniku oznacza „mój/moja/moje”: η πτήση μου to „mój lot”, η βαλίτσα μου to „moja walizka”. To jedna z najłatwiejszych i najbardziej użytecznych konstrukcji w greckim.`, practice: [`Zapytaj, gdzie jest bramka.`,`Powiedz, że zgubiłeś walizkę.`,`Powiedz: „To jest mój lot.”`,`Zapytaj, czy lot jest opóźniony.`,`Poproś o pomoc na lotnisku.`]},{day: 16, title: `Zakupy i pamiątki`, title_native: `Ψώνια και αναμνηστικά`, focus: `Kupujesz pamiątki w małym sklepie na Korfu. Nauczysz się pytać o rozmiar, kolor, cenę i możliwość zapakowania prezentu.`, vocab: [{el: `κατάστημα`, pl: `sklep`, ipa: `katastima`},{el: `αναμνηστικό`, pl: `pamiątka`, ipa: `anamnisitiko`},{el: `δώρο`, pl: `prezent`, ipa: `dhoro`},{el: `χρώμα`, pl: `kolor`, ipa: `chroma`},{el: `μέγεθος`, pl: `rozmiar`, ipa: `megethos`},{el: `μικρό`, pl: `małe`, ipa: `mikro`},{el: `μεγάλο`, pl: `duże`, ipa: `meghalo`},{el: `τσάντα`, pl: `torba`, ipa: `tsanda`},{el: `απόδειξη`, pl: `paragon`, ipa: `apodhiksi`},{el: `έκπτωση`, pl: `zniżka`, ipa: `ekptosi`}], phrases: [{el: `Μπορώ να το δω;`, pl: `Czy mogę to zobaczyć?`, ipa: `boro na to dho`},{el: `Έχετε άλλο χρώμα;`, pl: `Czy macie inny kolor?`, ipa: `echete alo chroma`},{el: `Έχετε μεγαλύτερο μέγεθος;`, pl: `Czy macie większy rozmiar?`, ipa: `echete meghalitero megethos`},{el: `Είναι για δώρο.`, pl: `To jest na prezent.`, ipa: `ine ja dhoro`},{el: `Μπορείτε να το τυλίξετε;`, pl: `Czy może pan/pani to zapakować?`, ipa: `borite na to tiliksete`},{el: `Μπορώ να έχω απόδειξη;`, pl: `Czy mogę dostać paragon?`, ipa: `boro na echo apodhiksi`}], grammar: `Το może znaczyć „to” jako zaimek odnoszący się do rzeczy rodzaju nijakiego lub ogólnie do przedmiotu w rozmowie. Μπορώ να το δω znaczy „Czy mogę to zobaczyć?”. Taka forma jest bardzo wygodna, gdy wskazujesz na coś w sklepie.`, practice: [`Zapytaj, czy możesz zobaczyć przedmiot.`,`Poproś o inny kolor.`,`Powiedz, że to jest prezent.`,`Poproś o zapakowanie prezentu.`,`Poproś o paragon.`]},{day: 17, title: `Ubrania i rozmiary`, title_native: `Ρούχα και μεγέθη`, focus: `W centrum handlowym w Atenach przymierzasz ubrania. Nauczysz się mówić, co pasuje, co jest za małe i gdzie jest przymierzalnia.`, vocab: [{el: `ρούχα`, pl: `ubrania`, ipa: `rucha`},{el: `μπλούζα`, pl: `bluzka, koszulka`, ipa: `bluza`},{el: `παντελόνι`, pl: `spodnie`, ipa: `pandeloni`},{el: `φόρεμα`, pl: `sukienka`, ipa: `forema`},{el: `παπούτσια`, pl: `buty`, ipa: `paputsia`},{el: `μέγεθος`, pl: `rozmiar`, ipa: `megethos`},{el: `μικρό`, pl: `małe`, ipa: `mikro`},{el: `μεγάλο`, pl: `duże`, ipa: `meghalo`},{el: `δοκιμαστήριο`, pl: `przymierzalnia`, ipa: `dhokimastirio`},{el: `ταιριάζει`, pl: `pasuje`, ipa: `teriazi`}], phrases: [{el: `Πού είναι το δοκιμαστήριο;`, pl: `Gdzie jest przymierzalnia?`, ipa: `pu ine to dhokimastirio`},{el: `Θέλω να το δοκιμάσω.`, pl: `Chcę to przymierzyć.`, ipa: `thelo na to dhokimaso`},{el: `Είναι πολύ μικρό.`, pl: `To jest za małe.`, ipa: `ine poli mikro`},{el: `Είναι πολύ μεγάλο.`, pl: `To jest za duże.`, ipa: `ine poli meghalo`},{el: `Μου ταιριάζει.`, pl: `To mi pasuje.`, ipa: `mu teriazi`},{el: `Δεν μου ταιριάζει.`, pl: `To mi nie pasuje.`, ipa: `dhen mu teriazi`}], grammar: `Πολύ oznacza „bardzo”, ale przy ubraniach często oddaje polskie „za”: πολύ μικρό to „za małe”, πολύ μεγάλο to „za duże”. Możesz używać tego także z innymi cechami, np. πολύ ακριβό, czyli „za drogie”.`, practice: [`Zapytaj o przymierzalnię.`,`Powiedz, że chcesz coś przymierzyć.`,`Powiedz, że ubranie jest za małe.`,`Powiedz, że buty są za duże.`,`Powiedz, że coś ci pasuje.`]},{day: 18, title: `Na plaży`, title_native: `Στην παραλία`, focus: `Spędzasz dzień na plaży na Zakynthos i potrzebujesz leżaka, wody oraz podstawowych zwrotów o pogodzie. Nauczysz się mówić o plażowych potrzebach.`, vocab: [{el: `παραλία`, pl: `plaża`, ipa: `paralia`},{el: `θάλασσα`, pl: `morze`, ipa: `thalasa`},{el: `ήλιος`, pl: `słońce`, ipa: `ilios`},{el: `ομπρέλα`, pl: `parasol`, ipa: `ombrela`},{el: `ξαπλώστρα`, pl: `leżak`, ipa: `ksaplostra`},{el: `πετσέτα`, pl: `ręcznik`, ipa: `petseta`},{el: `νερό`, pl: `woda`, ipa: `nero`},{el: `αντηλιακό`, pl: `krem przeciwsłoneczny`, ipa: `andiliako`},{el: `ζέστη`, pl: `upał`, ipa: `zesti`},{el: `κύμα`, pl: `fala`, ipa: `kima`}], phrases: [{el: `Θέλω μια ξαπλώστρα.`, pl: `Chcę jeden leżak.`, ipa: `thelo mia ksaplostra`},{el: `Έχετε ομπρέλα;`, pl: `Czy macie parasol?`, ipa: `echete ombrela`},{el: `Πόσο κάνει η ξαπλώστρα;`, pl: `Ile kosztuje leżak?`, ipa: `poso kani i ksaplostra`},{el: `Η θάλασσα είναι όμορφη.`, pl: `Morze jest piękne.`, ipa: `i thalasa ine omorfi`},{el: `Κάνει πολλή ζέστη.`, pl: `Jest bardzo gorąco.`, ipa: `kani poli zesti`},{el: `Χρειάζομαι αντηλιακό.`, pl: `Potrzebuję kremu przeciwsłonecznego.`, ipa: `chriazome andiliako`}], grammar: `Greckie κάνει często opisuje pogodę: Κάνει ζέστη znaczy „jest gorąco”. Dosłownie nie tłumaczy się tego jak po polsku, ale warto zapamiętać jako gotowy zwrot. Κάνει κρύο znaczy „jest zimno”.`, practice: [`Poproś o leżak.`,`Zapytaj o cenę leżaka.`,`Powiedz, że potrzebujesz kremu przeciwsłonecznego.`,`Powiedz, że morze jest piękne.`,`Powiedz, że jest bardzo gorąco.`]},{day: 19, title: `Pogoda i plany`, title_native: `Καιρός και σχέδια`, focus: `Planujesz wycieczkę na wyspie i musisz rozmawiać o pogodzie. Nauczysz się mówić o słońcu, deszczu, wietrze i zmianie planów.`, vocab: [{el: `καιρός`, pl: `pogoda`, ipa: `keros`},{el: `ήλιος`, pl: `słońce`, ipa: `ilios`},{el: `βροχή`, pl: `deszcz`, ipa: `vrochi`},{el: `αέρας`, pl: `wiatr`, ipa: `aeras`},{el: `σύννεφα`, pl: `chmury`, ipa: `sinefa`},{el: `κρύο`, pl: `zimno`, ipa: `krio`},{el: `ζέστη`, pl: `gorąco`, ipa: `zesti`},{el: `σήμερα`, pl: `dziś`, ipa: `simera`},{el: `αύριο`, pl: `jutro`, ipa: `avrio`},{el: `σχέδιο`, pl: `plan`, ipa: `schedhio`}], phrases: [{el: `Τι καιρό κάνει;`, pl: `Jaka jest pogoda?`, ipa: `ti kero kani`},{el: `Έχει ήλιο.`, pl: `Jest słonecznie.`, ipa: `echi ilio`},{el: `Βρέχει.`, pl: `Pada deszcz.`, ipa: `vrechi`},{el: `Έχει αέρα.`, pl: `Jest wietrznie.`, ipa: `echi aera`},{el: `Αλλάζουμε σχέδια.`, pl: `Zmieniamy plany.`, ipa: `alazume schedhia`},{el: `Αύριο θα πάμε.`, pl: `Pójdziemy/jedziemy jutro.`, ipa: `avrio tha pame`}], grammar: `Θα przed czasownikiem tworzy przyszłość. Θα πάμε znaczy „pójdziemy/pojedziemy”, θα φάμε „zjemy”, θα δούμε „zobaczymy”. To bardzo przydatne przy planowaniu następnego dnia.`, practice: [`Zapytaj, jaka jest pogoda.`,`Powiedz, że jest słonecznie.`,`Powiedz, że pada deszcz.`,`Zaproponuj zmianę planów.`,`Powiedz, że pojedziecie jutro.`]},{day: 20, title: `Zdrowie i apteka`, title_native: `Υγεία και φαρμακείο`, focus: `Szukasz apteki w Patras, bo boli cię głowa lub potrzebujesz podstawowego leku. Nauczysz się mówić o objawach i prosić o pomoc.`, vocab: [{el: `υγεία`, pl: `zdrowie`, ipa: `ijia`},{el: `φαρμακείο`, pl: `apteka`, ipa: `farmakio`},{el: `φάρμακο`, pl: `lek`, ipa: `farmako`},{el: `πονοκέφαλος`, pl: `ból głowy`, ipa: `ponokefalos`},{el: `πόνος`, pl: `ból`, ipa: `ponos`},{el: `στομάχι`, pl: `żołądek`, ipa: `stomachi`},{el: `πυρετός`, pl: `gorączka`, ipa: `piretos`},{el: `γιατρός`, pl: `lekarz`, ipa: `jatros`},{el: `βοήθεια`, pl: `pomoc`, ipa: `voithia`},{el: `συνταγή`, pl: `recepta`, ipa: `sindaji`}], phrases: [{el: `Πού είναι το φαρμακείο;`, pl: `Gdzie jest apteka?`, ipa: `pu ine to farmakio`},{el: `Έχω πονοκέφαλο.`, pl: `Boli mnie głowa.`, ipa: `echo ponokefalo`},{el: `Πονάει το στομάχι μου.`, pl: `Boli mnie żołądek.`, ipa: `ponai to stomachi mu`},{el: `Έχω πυρετό.`, pl: `Mam gorączkę.`, ipa: `echo pireto`},{el: `Χρειάζομαι γιατρό.`, pl: `Potrzebuję lekarza.`, ipa: `chriazome jatro`},{el: `Χρειάζεται συνταγή;`, pl: `Czy potrzebna jest recepta?`, ipa: `chriazete sindaji`}], grammar: `Έχω dosłownie znaczy „mam” i często opisuje dolegliwości: έχω πυρετό, έχω πονοκέφαλο. Przy bólu konkretnej części ciała możesz też użyć Πονάει..., czyli „boli...”. Το στομάχι μου to „mój żołądek”.`, practice: [`Zapytaj, gdzie jest apteka.`,`Powiedz, że boli cię głowa.`,`Powiedz, że masz gorączkę.`,`Zapytaj, czy potrzebna jest recepta.`,`Powiedz, że potrzebujesz lekarza.`]},{day: 21, title: `Nagłe sytuacje i bezpieczeństwo`, title_native: `Επείγουσες καταστάσεις και ασφάλεια`, focus: `W trudnej sytuacji za granicą musisz mówić jasno i szybko. Nauczysz się prosić o pomoc, zgłaszać problem i szukać policji.`, vocab: [{el: `επείγον`, pl: `nagły przypadek`, ipa: `epigon`},{el: `αστυνομία`, pl: `policja`, ipa: `astinomia`},{el: `νοσοκομείο`, pl: `szpital`, ipa: `nosokomio`},{el: `βοήθεια`, pl: `pomoc`, ipa: `voithia`},{el: `κίνδυνος`, pl: `niebezpieczeństwo`, ipa: `kindhinos`},{el: `χάθηκα`, pl: `zgubiłem się`, ipa: `chathika`},{el: `κλέψανε`, pl: `ukradli`, ipa: `klepsane`},{el: `πορτοφόλι`, pl: `portfel`, ipa: `portofoli`},{el: `κινητό`, pl: `telefon komórkowy`, ipa: `kinito`},{el: `διαβατήριο`, pl: `paszport`, ipa: `dhiavatirio`}], phrases: [{el: `Βοήθεια!`, pl: `Pomocy!`, ipa: `voithia`},{el: `Καλέστε την αστυνομία.`, pl: `Proszę wezwać policję.`, ipa: `kaleste tin astinomia`},{el: `Χάθηκα.`, pl: `Zgubiłem się.`, ipa: `chathika`},{el: `Μου έκλεψαν το πορτοφόλι.`, pl: `Ukradli mi portfel.`, ipa: `mu eklepsan to portofoli`},{el: `Χρειάζομαι νοσοκομείο.`, pl: `Potrzebuję szpitala.`, ipa: `chriazome nosokomio`},{el: `Μιλάτε αγγλικά;`, pl: `Czy mówi pan/pani po angielsku?`, ipa: `milate anglika`}], grammar: `W sytuacjach awaryjnych nie musisz budować idealnych zdań. Najważniejsze są krótkie komunikaty: Βοήθεια, Αστυνομία, Νοσοκομείο. Grecy często pomogą, jeśli jasno pokażesz, czego potrzebujesz.`, practice: [`Krzyknij po grecku „Pomocy!”`,`Poproś o wezwanie policji.`,`Powiedz, że zgubiłeś się.`,`Powiedz, że ukradli ci portfel.`,`Zapytaj, czy ktoś mówi po angielsku.`]},{day: 22, title: `Zwiedzanie i muzea`, title_native: `Αξιοθέατα και μουσεία`, focus: `Odwiedzasz Akropol i muzeum archeologiczne. Nauczysz się pytać o bilety, godziny otwarcia, audioprzewodnik i najważniejsze atrakcje.`, vocab: [{el: `μουσείο`, pl: `muzeum`, ipa: `musio`},{el: `αξιοθέατο`, pl: `atrakcja turystyczna`, ipa: `aksiotheato`},{el: `Ακρόπολη`, pl: `Akropol`, ipa: `akropoli`},{el: `εισιτήριο`, pl: `bilet`, ipa: `isitirio`},{el: `ξεναγός`, pl: `przewodnik`, ipa: `ksenagos`},{el: `χάρτης`, pl: `mapa`, ipa: `chartis`},{el: `φωτογραφία`, pl: `zdjęcie`, ipa: `fotografia`},{el: `είσοδος`, pl: `wejście`, ipa: `isodhos`},{el: `έξοδος`, pl: `wyjście`, ipa: `eksodhos`},{el: `ωράριο`, pl: `godziny otwarcia`, ipa: `orario`}], phrases: [{el: `Πόσο κάνει το εισιτήριο;`, pl: `Ile kosztuje bilet?`, ipa: `poso kani to isitirio`},{el: `Τι ώρα ανοίγει το μουσείο;`, pl: `O której otwiera muzeum?`, ipa: `ti ora aniji to musio`},{el: `Υπάρχει χάρτης;`, pl: `Czy jest mapa?`, ipa: `iparchi chartis`},{el: `Μπορώ να βγάλω φωτογραφίες;`, pl: `Czy mogę robić zdjęcia?`, ipa: `boro na vgalo fotografies`},{el: `Πού είναι η είσοδος;`, pl: `Gdzie jest wejście?`, ipa: `pu ine i isodhos`},{el: `Πού είναι η έξοδος;`, pl: `Gdzie jest wyjście?`, ipa: `pu ine i eksodhos`}], grammar: `Υπάρχει znaczy „jest/istnieje/znajduje się” i przydaje się do pytania o dostępność. Υπάρχει χάρτης; to „Czy jest mapa?”. Możesz też powiedzieć Υπάρχει τουαλέτα; czyli „Czy jest toaleta?”`, practice: [`Zapytaj o cenę biletu.`,`Zapytaj, o której otwiera muzeum.`,`Zapytaj, czy jest mapa.`,`Zapytaj, czy można robić zdjęcia.`,`Zapytaj o wejście i wyjście.`]},{day: 23, title: `Rezerwacje i plany wieczorne`, title_native: `Κρατήσεις και βραδινά σχέδια`, focus: `Chcesz zarezerwować stolik w restauracji w Atenach i zaplanować wieczór. Nauczysz się mówić o godzinie, liczbie osób i dostępności.`, vocab: [{el: `κράτηση`, pl: `rezerwacja`, ipa: `kratisi`},{el: `τραπέζι`, pl: `stolik`, ipa: `trapezi`},{el: `βράδυ`, pl: `wieczór`, ipa: `vradhi`},{el: `άτομα`, pl: `osoby`, ipa: `atoma`},{el: `διαθέσιμο`, pl: `dostępne`, ipa: `dhiathesimo`},{el: `ώρα`, pl: `godzina`, ipa: `ora`},{el: `σήμερα`, pl: `dziś`, ipa: `simera`},{el: `αύριο`, pl: `jutro`, ipa: `avrio`},{el: `τηλέφωνο`, pl: `telefon`, ipa: `tilefono`},{el: `όνομα`, pl: `nazwisko, imię`, ipa: `onoma`}], phrases: [{el: `Θέλω να κάνω κράτηση.`, pl: `Chcę zrobić rezerwację.`, ipa: `thelo na kano kratisi`},{el: `Για δύο άτομα.`, pl: `Dla dwóch osób.`, ipa: `ja dhio atoma`},{el: `Στις οκτώ, παρακαλώ.`, pl: `Na ósmą, proszę.`, ipa: `stis okto, parakalo`},{el: `Έχετε τραπέζι σήμερα;`, pl: `Czy macie stolik na dziś?`, ipa: `echete trapezi simera`},{el: `Σε ποιο όνομα;`, pl: `Na jakie nazwisko?`, ipa: `se pio onoma`},{el: `Το όνομά μου είναι Κάνον.`, pl: `Moje nazwisko to Cannon.`, ipa: `to onoma mu ine kanon`}], grammar: `Για oznacza „dla” lub „na” w wielu praktycznych sytuacjach. Για δύο άτομα to „dla dwóch osób”, για σήμερα może znaczyć „na dziś”. Zapamiętaj całe zwroty, bo często pojawiają się przy rezerwacjach.`, practice: [`Zarezerwuj stolik dla dwóch osób.`,`Poproś o rezerwację na godzinę ósmą.`,`Zapytaj, czy jest stolik na dziś.`,`Podaj swoje nazwisko.`,`Odegraj rozmowę telefoniczną z restauracją.`]},{day: 24, title: `Rozmowy towarzyskie`, title_native: `Κοινωνικές συζητήσεις`, focus: `Rozmawiasz z mieszkańcem w kawiarni na wyspie Naksos. Nauczysz się prowadzić krótką, miłą rozmowę o podróży, miejscu i wrażeniach.`, vocab: [{el: `ταξίδι`, pl: `podróż`, ipa: `taksidhi`},{el: `διακοπές`, pl: `wakacje`, ipa: `dhiakopes`},{el: `όμορφος`, pl: `piękny`, ipa: `omorfos`},{el: `ωραίος`, pl: `ładny, fajny`, ipa: `oreos`},{el: `πόλη`, pl: `miasto`, ipa: `poli`},{el: `νησί`, pl: `wyspa`, ipa: `nisi`},{el: `άνθρωποι`, pl: `ludzie`, ipa: `anthropi`},{el: `μου αρέσει`, pl: `podoba mi się`, ipa: `mu aresi`},{el: `καλός`, pl: `dobry`, ipa: `kalos`},{el: `φιλικός`, pl: `przyjazny`, ipa: `filikos`}], phrases: [{el: `Μου αρέσει η Ελλάδα.`, pl: `Podoba mi się Grecja.`, ipa: `mu aresi i eladha`},{el: `Το νησί είναι πολύ όμορφο.`, pl: `Wyspa jest bardzo piękna.`, ipa: `to nisi ine poli omorfo`},{el: `Οι άνθρωποι είναι φιλικοί.`, pl: `Ludzie są przyjaźni.`, ipa: `i anthropi ine filiki`},{el: `Είμαι εδώ για διακοπές.`, pl: `Jestem tu na wakacjach.`, ipa: `ime edho ja dhiakopes`},{el: `Πρώτη φορά στην Ελλάδα.`, pl: `Pierwszy raz w Grecji.`, ipa: `proti fora stin eladha`},{el: `Περνάω πολύ καλά.`, pl: `Bardzo dobrze się bawię.`, ipa: `pernao poli kala`}], grammar: `Μου αρέσει oznacza „podoba mi się” i działa inaczej niż polskie „lubię”. Mówisz Μου αρέσει η Ελλάδα, dosłownie „Grecja podoba się mnie”. To naturalna forma do mówienia o miejscach, jedzeniu i muzyce.`, practice: [`Powiedz, że podoba ci się Grecja.`,`Powiedz, że jesteś tu na wakacjach.`,`Powiedz, że to twój pierwszy raz w Grecji.`,`Skomentuj, że ludzie są przyjaźni.`,`Powiedz, że bardzo dobrze się bawisz.`]},{day: 25, title: `Zaproszenia i spotkania`, title_native: `Προσκλήσεις και συναντήσεις`, focus: `Poznajesz ludzi podczas podróży i chcesz zaproponować wspólną kawę albo spacer. Nauczysz się zapraszać, akceptować i odmawiać grzecznie.`, vocab: [{el: `συνάντηση`, pl: `spotkanie`, ipa: `sinandisi`},{el: `καφές`, pl: `kawa`, ipa: `kafes`},{el: `βόλτα`, pl: `spacer`, ipa: `volta`},{el: `μαζί`, pl: `razem`, ipa: `mazi`},{el: `σήμερα`, pl: `dziś`, ipa: `simera`},{el: `αύριο`, pl: `jutro`, ipa: `avrio`},{el: `μπορώ`, pl: `mogę`, ipa: `boro`},{el: `θέλω`, pl: `chcę`, ipa: `thelo`},{el: `ίσως`, pl: `może`, ipa: `isos`},{el: `ευχαρίστως`, pl: `z przyjemnością`, ipa: `efcharistos`}], phrases: [{el: `Θέλεις να πάμε για καφέ;`, pl: `Chcesz pójść na kawę?`, ipa: `thelis na pame ja kafe`},{el: `Πάμε μια βόλτα;`, pl: `Pójdziemy na spacer?`, ipa: `pame mia volta`},{el: `Ναι, ευχαρίστως.`, pl: `Tak, z przyjemnością.`, ipa: `ne, efcharistos`},{el: `Ίσως αύριο.`, pl: `Może jutro.`, ipa: `isos avrio`},{el: `Δεν μπορώ σήμερα.`, pl: `Dzisiaj nie mogę.`, ipa: `dhen boro simera`},{el: `Θα τα πούμε μετά.`, pl: `Porozmawiamy później.`, ipa: `tha ta pume meta`}], grammar: `Θέλεις to nieformalna forma „chcesz?” do jednej osoby. W bardziej uprzejmej wersji możesz powiedzieć Θέλετε. W podróży z nowymi znajomymi Θέλεις brzmi naturalnie, jeśli rozmowa jest swobodna.`, practice: [`Zaproś kogoś na kawę.`,`Zaproponuj spacer.`,`Przyjmij zaproszenie z radością.`,`Odmów, mówiąc, że dziś nie możesz.`,`Powiedz: „Może jutro.”`]},{day: 26, title: `Telefon, internet i problemy techniczne`, title_native: `Τηλέφωνο, ίντερνετ και τεχνικά προβλήματα`, focus: `Potrzebujesz Wi-Fi, ładowarki albo karty SIM w Atenach. Nauczysz się mówić o telefonie, internecie i podstawowych problemach.`, vocab: [{el: `τηλέφωνο`, pl: `telefon`, ipa: `tilefono`},{el: `κινητό`, pl: `komórka`, ipa: `kinito`},{el: `ίντερνετ`, pl: `internet`, ipa: `internet`},{el: `Wi-Fi`, pl: `Wi-Fi`, ipa: `wai-fai`},{el: `κωδικός`, pl: `hasło, kod`, ipa: `kodhikos`},{el: `φορτιστής`, pl: `ładowarka`, ipa: `fortistis`},{el: `μπαταρία`, pl: `bateria`, ipa: `bataria`},{el: `κάρτα SIM`, pl: `karta SIM`, ipa: `karta sim`},{el: `πρόβλημα`, pl: `problem`, ipa: `provlima`},{el: `λειτουργεί`, pl: `działa`, ipa: `liturji`}], phrases: [{el: `Έχετε Wi-Fi;`, pl: `Czy macie Wi-Fi?`, ipa: `echete wai-fai`},{el: `Ποιος είναι ο κωδικός;`, pl: `Jakie jest hasło?`, ipa: `pjos ine o kodhikos`},{el: `Το τηλέφωνό μου δεν λειτουργεί.`, pl: `Mój telefon nie działa.`, ipa: `to tilefono mu dhen liturji`},{el: `Χρειάζομαι φορτιστή.`, pl: `Potrzebuję ładowarki.`, ipa: `chriazome fortisti`},{el: `Πού μπορώ να αγοράσω κάρτα SIM;`, pl: `Gdzie mogę kupić kartę SIM?`, ipa: `pu boro na aghoraso karta sim`},{el: `Η μπαταρία είναι άδεια.`, pl: `Bateria jest rozładowana.`, ipa: `i bataria ine adhjia`}], grammar: `Δεν λειτουργεί znaczy „nie działa” i przyda się w hotelu, sklepie oraz przy sprzęcie. Możesz dodać rzeczownik przed tym zwrotem: Το Wi-Fi δεν λειτουργεί, Το τηλέφωνο δεν λειτουργεί. To bardzo praktyczny schemat.`, practice: [`Zapytaj o Wi-Fi.`,`Zapytaj o hasło do internetu.`,`Powiedz, że twój telefon nie działa.`,`Powiedz, że potrzebujesz ładowarki.`,`Zapytaj, gdzie możesz kupić kartę SIM.`]},{day: 27, title: `Wynajem auta i skutera`, title_native: `Ενοικίαση αυτοκινήτου και σκούτερ`, focus: `Na greckiej wyspie chcesz wynająć auto lub skuter. Nauczysz się pytać o cenę, dokumenty, ubezpieczenie i paliwo.`, vocab: [{el: `ενοικίαση`, pl: `wynajem`, ipa: `enikiasi`},{el: `αυτοκίνητο`, pl: `samochód`, ipa: `aftokinito`},{el: `σκούτερ`, pl: `skuter`, ipa: `skuter`},{el: `δίπλωμα`, pl: `prawo jazdy`, ipa: `dhíploma`},{el: `ασφάλεια`, pl: `ubezpieczenie`, ipa: `asfalia`},{el: `βενζίνη`, pl: `benzyna`, ipa: `venzini`},{el: `κράνος`, pl: `kask`, ipa: `kranos`},{el: `ημέρα`, pl: `dzień`, ipa: `imera`},{el: `τιμή`, pl: `cena`, ipa: `timi`},{el: `ζημιά`, pl: `uszkodzenie`, ipa: `zimia`}], phrases: [{el: `Θέλω να νοικιάσω αυτοκίνητο.`, pl: `Chcę wynająć samochód.`, ipa: `thelo na nikiaso aftokinito`},{el: `Πόσο κοστίζει την ημέρα;`, pl: `Ile kosztuje za dzień?`, ipa: `poso kostizi tin imera`},{el: `Χρειάζεται δίπλωμα;`, pl: `Czy potrzebne jest prawo jazdy?`, ipa: `chriazete dhíploma`},{el: `Η ασφάλεια περιλαμβάνεται;`, pl: `Czy ubezpieczenie jest wliczone?`, ipa: `i asfalia perilamvanete`},{el: `Έχετε κράνος;`, pl: `Czy macie kask?`, ipa: `echete kranos`},{el: `Πού είναι το βενζινάδικο;`, pl: `Gdzie jest stacja benzynowa?`, ipa: `pu ine to venzinadiko`}], grammar: `Να po czasowniku często wprowadza drugi czasownik, jak w Θέλω να νοικιάσω, czyli „chcę wynająć”. To jedna z najczęstszych konstrukcji w greckim. Możesz ją stosować z Θέλω να..., Μπορώ να..., Χρειάζομαι να....`, practice: [`Powiedz, że chcesz wynająć samochód.`,`Zapytaj o cenę za dzień.`,`Zapytaj, czy potrzebne jest prawo jazdy.`,`Zapytaj, czy ubezpieczenie jest wliczone.`,`Zapytaj o stację benzynową.`]},{day: 28, title: `W banku i przy płatnościach`, title_native: `Τράπεζα και πληρωμές`, focus: `Potrzebujesz gotówki, bankomatu albo wyjaśnienia płatności kartą. Nauczysz się używać praktycznych zwrotów finansowych.`, vocab: [{el: `τράπεζα`, pl: `bank`, ipa: `trapeza`},{el: `ATM`, pl: `bankomat`, ipa: `ei-ti-em`},{el: `μετρητά`, pl: `gotówka`, ipa: `metrita`},{el: `κάρτα`, pl: `karta`, ipa: `karta`},{el: `πληρωμή`, pl: `płatność`, ipa: `pliromi`},{el: `απόδειξη`, pl: `potwierdzenie, paragon`, ipa: `apodhiksi`},{el: `προμήθεια`, pl: `prowizja`, ipa: `promithia`},{el: `ανάληψη`, pl: `wypłata gotówki`, ipa: `analipsi`},{el: `λογαριασμός`, pl: `konto, rachunek`, ipa: `logariasmos`},{el: `υπογραφή`, pl: `podpis`, ipa: `ipografi`}], phrases: [{el: `Πού είναι το ATM;`, pl: `Gdzie jest bankomat?`, ipa: `pu ine to ei-ti-em`},{el: `Μπορώ να πληρώσω με κάρτα;`, pl: `Czy mogę zapłacić kartą?`, ipa: `boro na pliroso me karta`},{el: `Δέχεστε μετρητά;`, pl: `Czy przyjmujecie gotówkę?`, ipa: `dhecheste metrita`},{el: `Υπάρχει προμήθεια;`, pl: `Czy jest prowizja?`, ipa: `iparchi promithia`},{el: `Θέλω απόδειξη.`, pl: `Chcę potwierdzenie/paragon.`, ipa: `thelo apodhiksi`},{el: `Η κάρτα δεν λειτουργεί.`, pl: `Karta nie działa.`, ipa: `i karta dhen liturji`}], grammar: `Με oznacza „z” lub „za pomocą”. Με κάρτα to „kartą”, με μετρητά to „gotówką”. W płatnościach te dwa zwroty są bardzo częste i wystarczą w większości sytuacji.`, practice: [`Zapytaj, gdzie jest bankomat.`,`Zapytaj, czy można zapłacić kartą.`,`Powiedz, że karta nie działa.`,`Zapytaj, czy jest prowizja.`,`Poproś o potwierdzenie płatności.`]},{day: 29, title: `Problemy w hotelu i reklamacje`, title_native: `Προβλήματα στο ξενοδοχείο`, focus: `Coś nie działa w pokoju hotelowym: klimatyzacja, prysznic albo Wi-Fi. Nauczysz się zgłaszać problem spokojnie i konkretnie.`, vocab: [{el: `πρόβλημα`, pl: `problem`, ipa: `provlima`},{el: `δωμάτιο`, pl: `pokój`, ipa: `dhomatio`},{el: `κλιματισμός`, pl: `klimatyzacja`, ipa: `klimatismos`},{el: `ντους`, pl: `prysznic`, ipa: `dus`},{el: `ζεστό νερό`, pl: `ciepła woda`, ipa: `zesto nero`},{el: `κρύο νερό`, pl: `zimna woda`, ipa: `krio nero`},{el: `θόρυβος`, pl: `hałas`, ipa: `thorivos`},{el: `καθαρό`, pl: `czyste`, ipa: `katharo`},{el: `βρώμικο`, pl: `brudne`, ipa: `vromiko`},{el: `επισκευή`, pl: `naprawa`, ipa: `episkevi`}], phrases: [{el: `Έχουμε ένα πρόβλημα.`, pl: `Mamy problem.`, ipa: `echume ena provlima`},{el: `Ο κλιματισμός δεν λειτουργεί.`, pl: `Klimatyzacja nie działa.`, ipa: `o klimatismos dhen liturji`},{el: `Δεν έχει ζεστό νερό.`, pl: `Nie ma ciepłej wody.`, ipa: `dhen echi zesto nero`},{el: `Το δωμάτιο είναι βρώμικο.`, pl: `Pokój jest brudny.`, ipa: `to dhomatio ine vromiko`},{el: `Έχει πολύ θόρυβο.`, pl: `Jest bardzo głośno.`, ipa: `echi poli thorivo`},{el: `Μπορείτε να το διορθώσετε;`, pl: `Czy może pan/pani to naprawić?`, ipa: `borite na to dhiorthosete`}], grammar: `Έχει może znaczyć „ma” albo „jest/znajduje się” w pewnych zwrotach. Δεν έχει ζεστό νερό znaczy „nie ma ciepłej wody”. Έχει πολύ θόρυβο znaczy „jest dużo hałasu”.`, practice: [`Powiedz recepcji, że masz problem.`,`Zgłoś, że klimatyzacja nie działa.`,`Powiedz, że nie ma ciepłej wody.`,`Powiedz, że pokój jest brudny.`,`Poproś o naprawę problemu.`]},{day: 30, title: `Podsumowanie podróży i płynne sytuacje`, title_native: `Ανακεφαλαίωση ταξιδιού`, focus: `Ostatni dzień łączy wszystkie najważniejsze sytuacje: hotel, restaurację, transport, zakupy i rozmowy z ludźmi. Ćwiczysz pewność mówienia, nawet jeśli zdania są proste.`, vocab: [{el: `ταξίδι`, pl: `podróż`, ipa: `taksidhi`},{el: `εμπειρία`, pl: `doświadczenie`, ipa: `empiria`},{el: `ευχαριστώ`, pl: `dziękuję`, ipa: `efcharisto`},{el: `βοήθεια`, pl: `pomoc`, ipa: `voithia`},{el: `πληροφορία`, pl: `informacja`, ipa: `pliroforia`},{el: `χάρτης`, pl: `mapa`, ipa: `chartis`},{el: `κράτηση`, pl: `rezerwacja`, ipa: `kratisi`},{el: `εισιτήριο`, pl: `bilet`, ipa: `isitirio`},{el: `λογαριασμός`, pl: `rachunek`, ipa: `logariasmos`},{el: `αντίο`, pl: `do widzenia`, ipa: `adio`}], phrases: [{el: `Ευχαριστώ για τη βοήθεια.`, pl: `Dziękuję za pomoc.`, ipa: `efcharisto ja ti voithia`},{el: `Το ταξίδι ήταν υπέροχο.`, pl: `Podróż była wspaniała.`, ipa: `to taksidhi itan iperocho`},{el: `Έμαθα λίγα ελληνικά.`, pl: `Nauczyłem się trochę greckiego.`, ipa: `ematha liga elinika`},{el: `Μπορώ να ρωτήσω κάτι;`, pl: `Czy mogę o coś zapytać?`, ipa: `boro na rotiso kati`},{el: `Χρειάζομαι μια πληροφορία.`, pl: `Potrzebuję informacji.`, ipa: `chriazome mia pliroforia`},{el: `Θα ξανάρθω.`, pl: `Przyjadę znowu.`, ipa: `tha ksanartho`}], grammar: `Nawet proste greckie zdania robią dużą różnicę w podróży. Łącz znane elementy: Θέλω, Μπορώ, Πού είναι, Πόσο κάνει, Ευχαριστώ. Płynność zaczyna się od gotowych, pewnych fraz używanych w realnych sytuacjach.`, practice: [`Podziękuj komuś za pomoc.`,`Powiedz, że podróż była wspaniała.`,`Powiedz, że nauczyłeś się trochę greckiego.`,`Poproś o informację.`,`Ułóż krótką rozmowę obejmującą pytanie o drogę, zakup biletu i podziękowanie.`]}];

var CONVERSATIONS_PL_EL = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Atenach niedaleko placu Syntagma. Chcesz zamówić kawę, wodę i coś słodkiego, a potem poprosić o rachunek.`, lines: [{who: `them`, el: `Καλημέρα σας.`, pl: `Dzień dobry.`},{who: `you`, el: `Καλημέρα, έναν καφέ, παρακαλώ.`, pl: `Dzień dobry, kawę proszę.`},{who: `them`, el: `Με γάλα ή χωρίς γάλα;`, pl: `Z mlekiem czy bez mleka?`},{who: `you`, el: `Με γάλα, χωρίς ζάχαρη.`, pl: `Z mlekiem, bez cukru.`},{who: `them`, el: `Θέλετε κάτι άλλο;`, pl: `Czy chce pan/pani coś jeszcze?`},{who: `you`, el: `Ένα νερό και ένα γλυκό, παρακαλώ.`, pl: `Wodę i jeden deser, proszę.`},{who: `them`, el: `Για εδώ ή πακέτο;`, pl: `Na miejscu czy na wynos?`},{who: `you`, el: `Για εδώ, παρακαλώ.`, pl: `Na miejscu, proszę.`},{who: `them`, el: `Βεβαίως, καθίστε εδώ.`, pl: `Oczywiście, proszę usiąść tutaj.`},{who: `you`, el: `Ευχαριστώ πολύ.`, pl: `Bardzo dziękuję.`},{who: `you`, el: `Τον λογαριασμό, παρακαλώ.`, pl: `Rachunek, proszę.`},{who: `them`, el: `Αμέσως.`, pl: `Natychmiast.`}]},{id: 2, title: `Meldunek w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Nafplio. Masz rezerwację i chcesz zapytać o śniadanie oraz numer pokoju.`, lines: [{who: `them`, el: `Καλησπέρα σας, καλώς ήρθατε.`, pl: `Dobry wieczór, witamy.`},{who: `you`, el: `Καλησπέρα, έχω κράτηση.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, el: `Σε ποιο όνομα;`, pl: `Na jakie nazwisko?`},{who: `you`, el: `Το όνομά μου είναι Κάνον.`, pl: `Moje nazwisko to Cannon.`},{who: `them`, el: `Μπορώ να δω το διαβατήριό σας;`, pl: `Czy mogę zobaczyć pański/pani paszport?`},{who: `you`, el: `Βεβαίως, ορίστε.`, pl: `Oczywiście, proszę.`},{who: `them`, el: `Το δωμάτιό σας είναι στον δεύτερο όροφο.`, pl: `Pański/pani pokój jest na drugim piętrze.`},{who: `you`, el: `Πού είναι το ασανσέρ;`, pl: `Gdzie jest winda?`},{who: `them`, el: `Είναι δεξιά, δίπλα στη ρεσεψιόν.`, pl: `Jest po prawej, obok recepcji.`},{who: `you`, el: `Το πρωινό συμπεριλαμβάνεται;`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, el: `Ναι, από τις επτά μέχρι τις δέκα.`, pl: `Tak, od siódmej do dziesiątej.`},{who: `you`, el: `Ευχαριστώ για τη βοήθεια.`, pl: `Dziękuję za pomoc.`}]},{id: 3, title: `Pytanie o drogę do portu`, scene: `Spacerujesz po Chanii i chcesz dojść do starego portu. Zatrzymujesz mieszkańca i pytasz o najprostszą trasę.`, lines: [{who: `you`, el: `Συγγνώμη, πού είναι το λιμάνι;`, pl: `Przepraszam, gdzie jest port?`},{who: `them`, el: `Είναι κοντά, πηγαίνετε ευθεία.`, pl: `Jest blisko, proszę iść prosto.`},{who: `you`, el: `Μετά δεξιά ή αριστερά;`, pl: `Potem w prawo czy w lewo?`},{who: `them`, el: `Μετά στρίψτε αριστερά στην πλατεία.`, pl: `Potem proszę skręcić w lewo na placu.`},{who: `you`, el: `Είναι μακριά από εδώ;`, pl: `Czy to daleko stąd?`},{who: `them`, el: `Όχι, περίπου πέντε λεπτά.`, pl: `Nie, około pięciu minut.`},{who: `you`, el: `Υπάρχει χάρτης;`, pl: `Czy jest mapa?`},{who: `them`, el: `Ναι, κοιτάξτε εδώ.`, pl: `Tak, proszę spojrzeć tutaj.`},{who: `you`, el: `Ευχαριστώ πολύ.`, pl: `Bardzo dziękuję.`},{who: `them`, el: `Παρακαλώ, καλή βόλτα.`, pl: `Proszę bardzo, miłego spaceru.`},{who: `you`, el: `Καλή σας μέρα.`, pl: `Miłego dnia.`},{who: `them`, el: `Επίσης.`, pl: `Wzajemnie.`}]},{id: 4, title: `Kolacja w tawernie`, scene: `Jesteś w tawernie na Krecie i chcesz spróbować lokalnego jedzenia. Pytasz o rekomendację, danie bez mięsa i rachunek.`, lines: [{who: `them`, el: `Καλησπέρα, έχετε κράτηση;`, pl: `Dobry wieczór, mają państwo rezerwację?`},{who: `you`, el: `Όχι, έχετε τραπέζι για δύο άτομα;`, pl: `Nie, czy macie stolik dla dwóch osób?`},{who: `them`, el: `Ναι, παρακαλώ καθίστε εδώ.`, pl: `Tak, proszę usiąść tutaj.`},{who: `you`, el: `Μπορώ να δω το μενού;`, pl: `Czy mogę zobaczyć menu?`},{who: `them`, el: `Βεβαίως, ορίστε.`, pl: `Oczywiście, proszę.`},{who: `you`, el: `Τι προτείνετε;`, pl: `Co pan/pani poleca?`},{who: `them`, el: `Το ψάρι είναι πολύ φρέσκο σήμερα.`, pl: `Ryba jest dziś bardzo świeża.`},{who: `you`, el: `Έχετε κάτι χωρίς κρέας;`, pl: `Czy macie coś bez mięsa?`},{who: `them`, el: `Ναι, έχουμε σαλάτα και σπανακόπιτα.`, pl: `Tak, mamy sałatkę i placek ze szpinakiem.`},{who: `you`, el: `Θα ήθελα σπανακόπιτα και νερό.`, pl: `Chciałbym placek ze szpinakiem i wodę.`},{who: `them`, el: `Αμέσως.`, pl: `Natychmiast.`},{who: `you`, el: `Τον λογαριασμό, παρακαλώ.`, pl: `Rachunek, proszę.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś przy automacie biletowym w Atenach, ale nie jesteś pewien, który bilet kupić. Prosisz pracownika o pomoc w dojeździe do centrum.`, lines: [{who: `you`, el: `Συγγνώμη, χρειάζομαι βοήθεια.`, pl: `Przepraszam, potrzebuję pomocy.`},{who: `them`, el: `Βεβαίως, πού πηγαίνετε;`, pl: `Oczywiście, dokąd pan/pani jedzie?`},{who: `you`, el: `Πάω στο κέντρο.`, pl: `Jadę do centrum.`},{who: `them`, el: `Χρειάζεστε ένα εισιτήριο για το μετρό.`, pl: `Potrzebuje pan/pani biletu na metro.`},{who: `you`, el: `Πόσο κάνει;`, pl: `Ile kosztuje?`},{who: `them`, el: `Κάνει δύο ευρώ.`, pl: `Kosztuje dwa euro.`},{who: `you`, el: `Μπορώ να πληρώσω με κάρτα;`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, el: `Ναι, βάλτε την κάρτα εδώ.`, pl: `Tak, proszę włożyć kartę tutaj.`},{who: `you`, el: `Ποια γραμμή είναι;`, pl: `Która to linia?`},{who: `them`, el: `Η μπλε γραμμή πάει στο κέντρο.`, pl: `Niebieska linia jedzie do centrum.`},{who: `you`, el: `Ευχαριστώ πολύ.`, pl: `Bardzo dziękuję.`},{who: `them`, el: `Παρακαλώ.`, pl: `Proszę bardzo.`}]},{id: 6, title: `Zakupy w sklepie z pamiątkami`, scene: `W małym sklepie na Korfu oglądasz ceramikę i magnesy. Chcesz zapytać o cenę, inny kolor i zapakowanie prezentu.`, lines: [{who: `them`, el: `Γεια σας, μπορώ να βοηθήσω;`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, el: `Γεια σας, μπορώ να το δω;`, pl: `Dzień dobry, czy mogę to zobaczyć?`},{who: `them`, el: `Βεβαίως, ορίστε.`, pl: `Oczywiście, proszę.`},{who: `you`, el: `Πόσο κοστίζει αυτό;`, pl: `Ile to kosztuje?`},{who: `them`, el: `Κοστίζει δεκαπέντε ευρώ.`, pl: `Kosztuje piętnaście euro.`},{who: `you`, el: `Έχετε άλλο χρώμα;`, pl: `Czy macie inny kolor?`},{who: `them`, el: `Ναι, έχουμε μπλε και άσπρο.`, pl: `Tak, mamy niebieski i biały.`},{who: `you`, el: `Θα πάρω το μπλε.`, pl: `Wezmę niebieski.`},{who: `them`, el: `Είναι για δώρο;`, pl: `Czy to na prezent?`},{who: `you`, el: `Ναι, μπορείτε να το τυλίξετε;`, pl: `Tak, czy może pan/pani to zapakować?`},{who: `them`, el: `Φυσικά.`, pl: `Oczywiście.`},{who: `you`, el: `Ευχαριστώ, μπορώ να πληρώσω με κάρτα;`, pl: `Dziękuję, czy mogę zapłacić kartą?`}]},{id: 7, title: `W aptece`, scene: `W Patras boli cię głowa i szukasz czegoś prostego bez recepty. W aptece wyjaśniasz objawy i pytasz, czy potrzebna jest recepta.`, lines: [{who: `them`, el: `Καλημέρα σας, πώς μπορώ να βοηθήσω;`, pl: `Dzień dobry, jak mogę pomóc?`},{who: `you`, el: `Καλημέρα, έχω πονοκέφαλο.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, el: `Έχετε πυρετό;`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, el: `Όχι, δεν έχω πυρετό.`, pl: `Nie, nie mam gorączki.`},{who: `them`, el: `Έχετε αλλεργίες;`, pl: `Czy ma pan/pani alergie?`},{who: `you`, el: `Έχω αλλεργία στους ξηρούς καρπούς.`, pl: `Mam alergię na orzechy.`},{who: `them`, el: `Αυτό το φάρμακο είναι εντάξει.`, pl: `Ten lek jest w porządku.`},{who: `you`, el: `Χρειάζεται συνταγή;`, pl: `Czy potrzebna jest recepta?`},{who: `them`, el: `Όχι, δεν χρειάζεται.`, pl: `Nie, nie jest potrzebna.`},{who: `you`, el: `Πόσο κοστίζει;`, pl: `Ile kosztuje?`},{who: `them`, el: `Κοστίζει έξι ευρώ.`, pl: `Kosztuje sześć euro.`},{who: `you`, el: `Ευχαριστώ πολύ.`, pl: `Bardzo dziękuję.`}]},{id: 8, title: `Krótka rozmowa z mieszkańcem`, scene: `Siedzisz przy kawie na Naksos i rozmawiasz z lokalną osobą. Chcesz powiedzieć, że jesteś z Polski, podoba ci się Grecja i dobrze spędzasz czas.`, lines: [{who: `you`, el: `Γεια σας, είναι ελεύθερο εδώ;`, pl: `Dzień dobry, czy tutaj jest wolne?`},{who: `them`, el: `Ναι, παρακαλώ καθίστε.`, pl: `Tak, proszę usiąść.`},{who: `you`, el: `Ευχαριστώ, είμαι από την Πολωνία.`, pl: `Dziękuję, jestem z Polski.`},{who: `them`, el: `Καλώς ήρθατε στην Ελλάδα.`, pl: `Witamy w Grecji.`},{who: `you`, el: `Ευχαριστώ, μου αρέσει πολύ η Ελλάδα.`, pl: `Dziękuję, bardzo podoba mi się Grecja.`},{who: `them`, el: `Πρώτη φορά εδώ;`, pl: `Pierwszy raz tutaj?`},{who: `you`, el: `Ναι, πρώτη φορά στην Ελλάδα.`, pl: `Tak, pierwszy raz w Grecji.`},{who: `them`, el: `Πώς σας φαίνεται το νησί;`, pl: `Jak podoba się panu/pani wyspa?`},{who: `you`, el: `Το νησί είναι πολύ όμορφο.`, pl: `Wyspa jest bardzo piękna.`},{who: `them`, el: `Οι άνθρωποι εδώ είναι φιλικοί.`, pl: `Ludzie tutaj są przyjaźni.`},{who: `you`, el: `Ναι, περνάω πολύ καλά.`, pl: `Tak, bardzo dobrze się bawię.`},{who: `them`, el: `Καλή συνέχεια στο ταξίδι σας.`, pl: `Miłej dalszej podróży.`}]}];